      Create(ctx context.Context, p *entity.Product) error
      GetByID(ctx context.Context, id int64) (*entity.Product, error)
      // … остальные методы
  }
  ```

* **Usecase‑слой:** `usecase/product.go`  
  ```go
  type ProductUsecase struct {
      repo repository.ProductRepository
  }

  func (u *ProductUsecase) Create(ctx context.Context, p *entity.Product) error {
      if err := p.Validate(); err != nil {
          return err
      }
      return u.repo.Create(ctx, p)
  }
  ```

* **Тест сущности:** `entity/product_test.go`  
  ```go
  func TestUnitProductValidate(t *testing.T) {
      cases := []struct {
          name string
          p    entity.Product
          want error
      }{
          {"valid", entity.Product{Name: "Espresso", Price: 2.5}, nil},
          {"empty name", entity.Product{Name: "", Price: 2.5}, entity.ErrInvalidName},
          {"negative price", entity.Product{Name: "Latte", Price: -1}, entity.ErrInvalidPrice},
          // …другие кейсы
      }
      for _, tc := range cases {
          t.Run(tc.name, func(t *testing.T) {
              if got := tc.p.Validate(); !errors.Is(got, tc.want) {
                  t.Fatalf("expected %v, got %v", tc.want, got)
              }
          })
      }
  }
  ```

* **Тест корректного обрезания UTF‑8:** `entity/newsitem_test.go`  
